// ─── Factory Bulk Offer Upload ────────────────────────────────────────────────

/**
 * GET /getRFQFactoryTemplate
 *
 * Generates a pre-formatted xlsx template for the logged-in factory vendor.
 * The template has column headers, a Customer dropdown (all customers from DB),
 * a Price Terms dropdown, and 50 empty data rows with tall image cells.
 * The response is a binary xlsx file attachment.
 */
Customer.getRFQFactoryTemplate = async (req, result) => {
  const { getUserInfo } = require('../helpers/auth');
  const { generateTemplate } = require('../helpers/rfqBulkImport');

  try {
    const token = req.headers.authorization;
    const userInfo = await getUserInfo(token);
    const vendorName = userInfo ? (userInfo.name || 'Factory') : 'Factory';

    const allCustomers = await sql.customers.findAll({
      attributes: ['customers_id', 'customers_name'],
      order: [['customers_name', 'ASC']],
      raw: true,
    });
    const customerList = allCustomers
      .filter(c => c.customers_name)
      .map(c => ({ id: c.customers_id, name: c.customers_name }));

    const buffer = await generateTemplate(vendorName, customerList);
    result(null, { buffer, vendorName });
  } catch (err) {
    result(err, null);
  }
};

/**
 * Translate a Sequelize/upload error into a short bilingual reason string
 * suitable for showing directly to a factory user.
 *
 * The full technical error is always logged server-side; this function only
 * produces the human-readable portion that goes in the API response.
 */
function describeImportRowError(err, row) {
  const name = err.name || '';
  const msg  = (err.message || '').toLowerCase();

  // ── Sequelize constraint / validation errors ───────────────────────────
  if (name === 'SequelizeUniqueConstraintError') {
    const field = err.errors?.[0]?.path || '';
    return field
      ? `Duplicate value in "${field}" · "${field}"字段值重复`
      : 'Duplicate record · 记录重复';
  }

  if (name === 'SequelizeForeignKeyConstraintError') {
    // All FK values in this import (customer, step, factory) are either
    // system-provided or resolved before the DB call — a constraint error here
    // is a system problem, not a factory data problem.
    return 'System reference error — please contact support · 系统引用错误，请联系客服';
  }

  if (name === 'SequelizeValidationError') {
    const fields = (err.errors || []).map(e => e.path).filter(Boolean);
    if (fields.length) {
      return `Invalid value in: ${fields.join(', ')} · 字段值无效：${fields.join('、')}`;
    }
    return 'Validation failed · 数据验证失败';
  }

  if (name === 'SequelizeDatabaseError') {
    if (msg.includes('null value') || msg.includes('not-null')) {
      // Extract column name from Postgres error if present
      const colMatch = err.message.match(/column "([^"]+)"/);
      const col = colMatch ? colMatch[1] : '';
      return col
        ? `Required field missing: ${col} · 必填字段为空：${col}`
        : 'Required field is empty · 必填字段为空';
    }
    if (msg.includes('value too long') || msg.includes('character varying')) {
      return 'A value is too long for its field · 某字段内容超出长度限制';
    }
    if (msg.includes('invalid input syntax')) {
      const typeMatch = err.message.match(/type "([^"]+)"/);
      const type = typeMatch ? typeMatch[1] : 'field';
      return `Invalid format for ${type} (expected a number?) · ${type}格式无效（是否应为数字？）`;
    }
    return 'Database error · 数据库错误';
  }

  // ── Network / storage errors ───────────────────────────────────────────
  if (msg.includes('econnrefused') || msg.includes('enotfound') || msg.includes('etimedout')) {
    return 'Network error — please try again · 网络错误，请重试';
  }

  // ── Fallback: first 80 chars of the raw message, still bilingual label ─
  const short = (err.message || 'unknown error').slice(0, 80);
  return `${short} · 导入失败`;
}

/**
 * POST /importFactoryRFQ   (multipart/form-data, field: "file")
 *
 * Parses a completed factory offer xlsx and creates:
 *   1. One RFQGroup named by the factory (req.body.groupName)
 *   2. One RFQItem per data row  (price code: foff-XXXX, step: @factories)
 *   3. One RFQVendor quote record per item (linked to the uploading factory)
 *   4. Images embedded in xlsx cells are uploaded to DigitalOcean Spaces
 *
 * Returns a summary: { created, items, errors, groupId, groupName }
 */
Customer.importFactoryRFQ = async (req, result) => {
  const { getUserInfo } = require('../helpers/auth');
  const { parseImport, getNextFoffPriceCodes } = require('../helpers/rfqBulkImport');
  const { uploadBufferToSpaces } = require('../helpers/digitalocean');

  try {
    const token = req.headers.authorization;
    const userInfo = await getUserInfo(token);
    const factoryId = userInfo ? userInfo.factory_id : null;

    const groupName = (req.body.groupName || '').trim() || 'Factory Upload';
    if (!req.file || !req.file.buffer) {
      return result(null, { created: 0, errors: ['No file received · 未收到文件'] });
    }

    // Parse the uploaded xlsx — catch format errors cleanly so they reach the
    // user as a readable message instead of a 500.
    let rows, images;
    try {
      ({ rows, images } = await parseImport(req.file.buffer));
    } catch (parseErr) {
      console.warn('importFactoryRFQ: parse error:', parseErr.message);
      return result(null, {
        created: 0,
        errors: ['Invalid file format — please use the official template · 文件格式不正确，请使用官方模板'],
      });
    }

    if (rows.length === 0) {
      return result(null, { created: 0, errors: ['No data rows found · 未找到数据行，请至少填写一行'] });
    }

    // Build customer lookup map (name → id, case-insensitive)
    const allCustomers = await sql.customers.findAll({
      attributes: ['customers_id', 'customers_name'],
      raw: true,
    });
    const customerMap = {};
    allCustomers.forEach(c => {
      if (c.customers_name) customerMap[c.customers_name.toLowerCase().trim()] = c.customers_id;
    });

    // Resolve @factories step ID
    const factoriesStep = await sql.RFQStep.findOne({ where: { RFQStep_title: '@factories' } });
    const stepId = factoriesStep ? factoriesStep.RFQStep_id : 3;

    // Allocate price codes for all rows upfront (atomic sequence)
    const priceCodes = await getNextFoffPriceCodes(sql, rows.length, Op);

    // Create the RFQ Group
    const group = await sql.RFQGroup.create({
      RFQGroup_name: groupName,
      IsLegacy: false,
      user_id_fk: null,
    });
    const groupId = group.dataValues.RFQGroup_id;

    const created = [];
    const errors = [];

    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];
      try {
        // Best-effort lookup — if the factory's dropdown value doesn't match
        // (e.g. template was stale), we store null rather than failing the row.
        const customerId = customerMap[(row.customer || '').toLowerCase().trim()] || null;

        // Upload image if the factory embedded one in this row
        let pictureFull = null;
        let pictureThumb = null;
        if (images[row._rowNumber]) {
          const { buffer: imgBuf, extension } = images[row._rowNumber];
          const ts = Date.now() + i; // unique per row
          const ext = (extension || 'jpeg').replace(/^\./, '');
          const contentType = ext === 'png' ? 'image/png' : 'image/jpeg';
          const imgKey = `images-${ts}-foff-offer.${ext}`;
          try {
            pictureFull = await uploadBufferToSpaces(imgBuf, imgKey, contentType);
            pictureThumb = pictureFull; // same file; thumbnail resizing can be added later
          } catch (imgUploadErr) {
            console.warn(`importFactoryRFQ: image upload failed for row ${i + 1}:`, imgUploadErr.message);
          }
        }

        // Create RFQItem
        const item = await sql.RFQItem.create({
          rfqItem_style_number:    priceCodes[i],
          rfqItem_description:     row.description,
          rfqItem_customer:        customerId,
          rfqItem_quantity:        row.quantity != null ? String(row.quantity) : null,
          rfqItem_case_pack:       row.case_pack != null ? String(row.case_pack) : null,
          rfqItem_picture:         pictureFull,
          rfqItem_picturethumb:    pictureThumb,
          rfqItem_rfq_group:       groupId,
          rfqItem_step:            stepId,
          rfqItem_choosen_vendor:  factoryId,
          rfqItem_factories_step_at: new Date().toISOString(),
          rfqItem_notes:           row.notes || null,
        });
        const itemId = item.dataValues.rfqItem_id;

        // Calculate CBM/pc from carton dimensions
        let cbmPc = null;
        const l = parseFloat(row.carton_length);
        const w = parseFloat(row.carton_width);
        const h = parseFloat(row.carton_height);
        const casePack = parseFloat(row.case_pack) || 1;
        if (l > 0 && w > 0 && h > 0) {
          cbmPc = ((l * w * h) / 1000000 / casePack).toFixed(6);
        }

        // Create RFQVendor quote record
        await sql.RFQVendor.create({
          vendor_id_fk:      factoryId,
          RFQitem_id_fk:     itemId,
          RFQVendor_amount:  row.quote_price != null ? String(row.quote_price) : null,
          carton_length:     l > 0 ? l : null,
          carton_width:      w > 0 ? w : null,
          carton_height:     h > 0 ? h : null,
          RFQVendor_cbm_pc:  cbmPc,
          lead_time:         row.lead_time != null ? Math.round(row.lead_time) : null,
          price_terms:       row.price_terms || 'FOB',
          fob_country:       row.fob_country || null,
          fob_port:          row.fob_port || null,
          RFQVendor_note:    row.notes || null,
          quote_date:        new Date().toISOString().split('T')[0],
          req_status:        2, // 2 = quoted
        });

        created.push({ priceCode: priceCodes[i], description: row.description });
      } catch (rowErr) {
        console.error(`importFactoryRFQ row ${i + 1} error:`, rowErr);
        const shortDesc = (row.description || '').slice(0, 40);
        const reason = describeImportRowError(rowErr, row);
        errors.push(`Row ${i + 1} "${shortDesc}": ${reason}`);
      }
    }

    result(null, { created: created.length, items: created, errors, groupId, groupName });
  } catch (err) {
    console.error('importFactoryRFQ top-level error:', err);
    result(err, null);
  }
};

module.exports = Customer;

