/**
 * Parse an uploaded factory offer xlsx file.
 *
 * Returns:
 *   rows  — array of data objects, one per non-empty data row
 *   images — map of worksheet row number (1-indexed) → { buffer, extension }
 *
 * @param {Buffer} buffer
 * @returns {Promise<{ rows: Array, images: Object }>}
 */
exports.parseImport = async (buffer) => {
  const workbook = new ExcelJS.Workbook();
  await workbook.xlsx.load(buffer);

  // Use the first non-hidden, non-lookup worksheet
  let ws = workbook.worksheets.find(s =>
    s.state !== 'hidden' && s.name.toLowerCase() !== 'lookups' && s.name.toLowerCase() !== 'instructions'
  );
  if (!ws) ws = workbook.worksheets[0];
  if (!ws) throw new Error('No worksheet found · 文件中未找到工作表');

  // ── Locate the header row (the row whose first cell is "Description") ──
  let headerRowNum = null;
  ws.eachRow((row, rowNumber) => {
    if (headerRowNum) return;
    const first = String(row.getCell(1).value || '').trim();
    if (first.toLowerCase() === 'description') headerRowNum = rowNumber;
  });

  if (!headerRowNum) {
    throw new Error('Header row not found · 未找到标题行，请使用官方模板');
  }

  // ── Build column index map from header labels ─────────────────────────
  const colMap = {};
  ws.getRow(headerRowNum).eachCell((cell, colNumber) => {
    const val = String(cell.value || '').toLowerCase();
    if (val.includes('description'))      colMap.description    = colNumber;
    else if (val.includes('customer'))    colMap.customer       = colNumber;
    else if (val.includes('quantity'))    colMap.quantity       = colNumber;
    else if (val.includes('case pack'))   colMap.case_pack      = colNumber;
    else if (val.includes('quote price')) colMap.quote_price    = colNumber;
    else if (val.includes('price terms')) colMap.price_terms    = colNumber;
    else if (val.includes('carton length')) colMap.carton_length = colNumber;
    else if (val.includes('carton width'))  colMap.carton_width  = colNumber;
    else if (val.includes('carton height')) colMap.carton_height = colNumber;
    else if (val.includes('lead time'))   colMap.lead_time      = colNumber;
    else if (val.includes('fob country')) colMap.fob_country    = colNumber;
    else if (val.includes('fob port'))    colMap.fob_port       = colNumber;
    else if (val.includes('notes'))       colMap.notes          = colNumber;
  });

  const dataStart = headerRowNum + 1;

  // ── Extract data rows ─────────────────────────────────────────────────
  const rows = [];
  ws.eachRow((row, rowNumber) => {
    if (rowNumber < dataStart) return;

    const descCell = row.getCell(colMap.description || 1);
    const desc = String(descCell.value || '').trim();
    if (!desc) return; // skip empty rows

    const getStr = (col) => String(row.getCell(col || 1).value || '').trim();
    const getNum = (col) => {
      const v = row.getCell(col || 1).value;
      if (v === null || v === undefined || v === '') return null;
      const n = parseFloat(String(v));
      return isNaN(n) ? null : n;
    };

    rows.push({
      description:   desc,
      customer:      getStr(colMap.customer),
      quantity:      getNum(colMap.quantity),
      case_pack:     getNum(colMap.case_pack),
      quote_price:   getNum(colMap.quote_price),
      price_terms:   getStr(colMap.price_terms) || 'FOB',
      carton_length: getNum(colMap.carton_length),
      carton_width:  getNum(colMap.carton_width),
      carton_height: getNum(colMap.carton_height),
      lead_time:     getNum(colMap.lead_time),
      fob_country:   getStr(colMap.fob_country),
      fob_port:      getStr(colMap.fob_port),
      notes:         getStr(colMap.notes),
      _rowNumber:    rowNumber,
    });
  });

  // ── Extract embedded images ───────────────────────────────────────────
  // ExcelJS exposes workbook.getImages() which returns [{imageId, range: {tl:{col,row},...}}]
  // range.tl.row is 0-indexed (row 1 of the sheet = index 0)
  const images = {};
  try {
    const embeddedImages = workbook.getImages();
    for (const img of embeddedImages) {
      // Convert 0-indexed ExcelJS row to 1-indexed worksheet row number
      const worksheetRowNum = Math.floor(img.range.tl.row) + 1;
      const imageData = workbook.getImage(img.imageId);
      if (imageData && imageData.buffer && worksheetRowNum >= dataStart) {
        // Only keep the first image per row
        if (!images[worksheetRowNum]) {
          images[worksheetRowNum] = {
            buffer: Buffer.isBuffer(imageData.buffer)
              ? imageData.buffer
              : Buffer.from(imageData.buffer),
            extension: imageData.extension || 'jpeg',
          };
        }
      }
    }
  } catch (imgErr) {
    // Image extraction is best-effort; don't fail the whole import
    console.warn('rfqBulkImport: image extraction error (non-fatal):', imgErr.message);
  }

  return { rows, images };
};

/**
 * Allocate the next `count` sequential foff-XXXX price codes globally.
 *
 * @param {object} sql - Sequelize model namespace
 * @param {number} count
 * @param {object} Op - Sequelize Op
 * @returns {Promise<string[]>}
 */
exports.getNextFoffPriceCodes = async (sql, count, Op) => {
  const existing = await sql.RFQItem.findAll({
    where: { rfqItem_style_number: { [Op.like]: 'foff-%' } },
    attributes: ['rfqItem_style_number'],
    raw: true,
  });

  let maxNum = 0;
  for (const item of existing) {
    const match = String(item.rfqItem_style_number || '').match(/^foff-(\d+)$/);
    if (match) {
      const n = parseInt(match[1], 10);
      if (n > maxNum) maxNum = n;
    }
  }

  return Array.from({ length: count }, (_, i) => {
    const num = maxNum + i + 1;
    return `foff-${String(num).padStart(4, '0')}`;
  });
};

