  { id: 1, name: 'Acme Retail' },
  { id: 2, name: 'Globex' },
];

describe('generateTemplate', () => {
  test('opens to the Offer Template tab, not the hidden Lookups sheet', async () => {
    const buffer = await generateTemplate('Sample Factory', CUSTOMERS);

    const workbook = new ExcelJS.Workbook();
    await workbook.xlsx.load(buffer);

    // activeTab is the 0-based position of the tab Excel selects on open.
    const activeTab = workbook.views[0] && workbook.views[0].activeTab;
    const activeSheet = workbook.worksheets[activeTab];

    expect(activeSheet).toBeDefined();
    expect(activeSheet.name).toBe('Offer Template');

    // Guard the original bug: the Lookups sheet must stay hidden and must not
    // be the tab presented to the user.
    const lookups = workbook.getWorksheet('Lookups');
    expect(lookups.state).toBe('hidden');
    expect(activeSheet.name).not.toBe('Lookups');
  });

  test('Instructions sheet is bilingual (English + Simplified Chinese)', async () => {
    const buffer = await generateTemplate('Sample Factory', CUSTOMERS);

    const workbook = new ExcelJS.Workbook();
    await workbook.xlsx.load(buffer);

    const instr = workbook.getWorksheet('Instructions');
    expect(instr).toBeDefined();

    // Collect all text in the first column.
    let text = '';
    instr.eachRow((row) => { text += String(row.getCell(1).value || '') + '\n'; });

    // English heading and its Chinese translation both present.
    expect(text).toContain('FACTORY OFFER TEMPLATE — HOW TO FILL IN');
    expect(text).toContain('工厂报价模板 — 填写说明');
    // A representative field instruction, both languages.
    expect(text).toContain('QUOTE PRICE');
    expect(text).toContain('报价');
  });
});

